OST['discount'] : 0;		$amount = isset($_POST['amount']) ? $_POST['amount'] : 0;		$bank_amount = isset($_POST['bank_amount']) ? $_POST['bank_amount'] : 0;		$user_id = $this->session->userdata('user_id');				$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				if(count($_POST) > 0){						if($cust_trans_id){				$this->rpc_service->setSP("dbo.sp_cust_trans_edit");				$this->rpc_service->addField('cust_trans_id',$cust_trans_id);			} else {				$this->rpc_service->setSP("dbo.sp_cust_trans_add");			}						foreach($paymentlist as $dt_data){				$this->rpc_service->addAttributeChild('dt' ,$dt_data);			}						$this->rpc_service->addField('cust_trans_no',$cust_trans_no);			$this->rpc_service->addField('cust_trans_date',$cust_trans_date);			$this->rpc_service->addField('cust_trans_due_date',$cust_trans_date);			$this->rpc_service->addField('cust_trans_type_id',$cust_trans_type_id);			$this->rpc_service->addField('partner_id',$partner_id);			$this->rpc_service->addField('currencies_id',$currencies_id);			$this->rpc_service->addField('bank_id',$bank_id);			$this->rpc_service->addField('bank_charge',$bank_charge);			$this->rpc_service->addField('discount',$discount);			$this->rpc_service->addField('amount',$amount);			$this->rpc_service->addField('bank_amount',$bank_amount);							$result = $this->rpc_service->resultJSON();						$data = array();			if(isset($result)){				if(isset($result['valid'])){					if($result['valid']){						if(isset($result['data'])){							$data_result = json_decode($result['data'],true);														$return['valid'] = $result['valid'];							$return['status_code'] = $result['no'];							$return['message'] = $result['des'];							$return['cust_trans_id'] = $data_result['cust_trans_id'];							$return['new_cust_trans'] = $data_result['new_cust_trans'];							$return['partner_id'] = $partner_id;							$return['currencies_id'] = $currencies