oaddata['recordsFiltered'] = $recordsFiltered;		$loaddata['recordsTotal'] = $recordsTotal;		$loaddata['data'] = $data;		echo json_encode($loaddata);	}		function post_add_edit_detail(){		$this->authentication->plainlayout();		$parameter = array();		$return = array();				$cust_trans_index = isset($_POST['cust_trans_index']) ? $_POST['cust_trans_index'] : false;		$cust_trans_id = isset($_POST['cust_trans_id']) ? $_POST['cust_trans_id'] : 0;		$cust_trans_detail_id = isset($_POST['cust_trans_detail_id']) ? $_POST['cust_trans_detail_id'] : '';		$item_id = isset($_POST['item_id']) ? $_POST['item_id'] : '';		$quantity_ordered = isset($_POST['quantity_ordered']) ? $_POST['quantity_ordered'] : '';		$uom_id = isset($_POST['uom_id']) ? $_POST['uom_id'] : '';		$conversion = isset($_POST['conversion']) ? $_POST['conversion'] : '';		$unit_price = isset($_POST['unit_price']) ? $_POST['unit_price'] : '';		$user_id = $this->session->userdata('user_id');				if($cust_trans_index){			$seq = $cust_trans_index;		} else {			$seq = $this->session->userdata('cust_trans_seq');			if(!$seq){				$seq = 0;			}			$seq += 1;		}		$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				if(count($_POST) > 0){			if($cust_trans_detail_id){				$this->rpc_service->setSP("dbo.sp_cust_trans_detail_edit");				$this->rpc_service->addField('cust_trans_detail_id',$cust_trans_detail_id);			} else {				$this->rpc_service->setSP("dbo.sp_cust_trans_detail_add");			}						$this->rpc_service->addField('cust_trans_id',$cust_trans_id);			$this->rpc_service->addField('item_id',$item_id);			$this->rpc_service->addField('quantity_ordered',$quantity_ordered);			$this->rpc_service->addField('uom_id',$uom_id);			$this->rpc_service->addField('conversion',$conversion);			$this->rpc_service->addField('unit_price',$unit_price);						$result = $this->rpc_service->resultJSON();						$data = array();			if(isse