erdata('cust_trans');		if(isset($sales[$cust_trans_index])){						if($sales[$cust_trans_index]['cust_trans_detail_id'] != '0'){				$cust_trans_detail_id = $sales[$cust_trans_index]['cust_trans_detail_id'];								$this->rpc_service->setSP("dbo.sp_cust_trans_detail_delete");				$this->rpc_service->addField('cust_trans_detail_id',$cust_trans_detail_id);								$result = $this->rpc_service->resultJSON();			}						unset($sales[$cust_trans_index]);			$newdata = array(				'cust_trans'  => $sales			);			$this->session->set_userdata($newdata);					}								$result = array();		$return['valid'] = false;		$return['status_code'] = 501;		$return['message'] = "Internal Server Error";				$return['valid'] = true;		$return['status_code'] = '00';		$return['message'] = 'success';				echo json_encode($return);	}		function loaddata_cust_trans_payment_item(){		$this->authentication->plainlayout();		$return = array();				$field = $this->cust_trans_payment_item_table();				$lock_data = isset($_POST['lock_data']) ? $_POST['lock_data'] : 0;		$cust_trans_id = isset($_POST['cust_trans_id']) ? $_POST['cust_trans_id'] : '';		$partner_id = isset($_POST['partner_id']) ? $_POST['partner_id'] : '';		$currencies_id = isset($_POST['currencies_id']) ? $_POST['currencies_id'] : '';		$methodid = isset($_REQUEST['methodid']) ? is_numeric($_REQUEST['methodid']) ? $_REQUEST['methodid']  : -1 : -1;				$page = isset($_POST['page'])?$_POST['page']:1; // get the requested page         $rows = isset($_POST['rows'])?$_POST['rows']:10; // get how many rows we want to have into the grid         $sidx = isset($_POST['sidx'])?$_POST['sidx']:'r1'; // get index row - i.e. user click to sort         $sord = isset($_POST['sord'])?$_POST['sord']:'asc'; // get the direction 		$search = true; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;				$decode_filterRules = json_decode($filterRules,true);				if(isset($decode_filterRules)){			if(isset($decode_filterRules['rules'])){				$rules = $decode_filterRules['rules'];			} else {				$rules = array();			}		} else {			$decode_filterRules['groupOp'] = 'AND';			$rules = array();		}						$extra_param = array();						$extra_param['where']['0']['field'] = 'r9';		$extra_param['where']['0']['data'] = $partner_id;		$extra_param['where']['1']['field'] = 'r10';		$extra_param['where']['1']['data'] = $currencies_id;				if($cust_trans_id){			if($lock_data == 1){				$extra_param['where']['2']['field'] = 'r11';				$extra_param['where']['2']['data'] = $cust_trans_id;				$extra_param['where']['3']['field'] = 'r12';				$extra_param['where']['3']['data'] = $cust_trans_id;			} else {				$extra_param['where']['2']['field'] = 'r11';				$extra_param['where']['2']['data'] = $cust_trans_id;			}		}								if(isset($extra_param['where'])){			foreach($extra_param['where'] as $dt_where){				$have_key = false;								foreach($rules as $key => $value){					if($value['field'] == $dt_where['field']){						$have_key = true;						$rules[$key]['data'] = $dt_where['data'];						break;					}				}								if(!$have_key){					$data_where = array();					$data_where['field'] = $dt_where['field'];					$data_where['op'] = 'eq';					$data_where['data'] = $dt_where['data'];					$rules[] = $data_where;				}			}		}				$decode_filterRules['rules'] = $rules;		$filterRules = json_encode($decode_filterRules);				$limit =  $rows;		$offset =  $rows * ($page - 1);				$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;								$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error";							$sp = "dbo.sp_ecc_load_view_data";			$this->rpc_service_portal->setSP($sp);		if($cust_trans_id){			if($lock_data == 1){							} else {				$this->rpc_service_portal->addField('view','view_cust_trans_payment_detail');			}		} else {			$this->rpc_service_portal->addField('view','view_cust_trans_payment_item_new');		}				$this->rpc_service_portal->addField('sort',$sort);		$this->rpc_service_portal->addField('limit',$limit);		$this->rpc_service_portal->addField('offset',$offset);				$this->rpc_service_portal->setWhere($search,$filterRules,$field);				$result = $this->rpc_service_portal->resultJSON();			$data_result = json_decode($result['data'],true);				if(isset($data_result['detail']['result_count'])){			$records = $data_result['detail']['result_count'];			$total = ceil($data_result['detail']['result_count'] / $limit);		} else {			$records = 0;			$total = 0;		}				$responce = new stdclass();		$responce->page = $page;		$responce->records = $records;		$responce->total = $total;		$i=0; 		if($data_result){			if(isset($data_result['xrow'])){				foreach($data_result['xrow'] as $key=>$value){					foreach ($value as $k => $v) {						$responce->rows[$i][$k] = $v;					} 															$i++;				}			}		}					$return = json_encode($responce);					echo $return;	}}?>